    `content_scope` STRING COMMENT 'Defines whether the deal covers a single title, an entire series, a specific season, a curated package of multiple titles, or a content library. | Column content_scope (STRING) in rights.rights_syndication_deal. Valid values are `single-title|series|season|package|library`',
    `contract_document_reference` STRING COMMENT 'Reference identifier or file path to the signed syndication contract document stored in the document management system. | Column contract_document_reference (STRING) in rights.rights_syndication_deal',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in rights.rights_syndication_deal',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this syndication deal record was first created in the system. | Column created_timestamp (TIMESTAMP) in rights.rights_syndication_deal',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts in this deal (e.g., USD, GBP, EUR). | Column currency_code (STRING) in rights.rights_syndication_deal. Valid values are `^[A-Z]{3}$`',
    `deal_end_date` DATE COMMENT 'Date on which the syndication rights expire and the licensee must cease distribution. Null indicates an open-ended or perpetual deal. | Column deal_end_date (DATE) in rights.rights_syndication_deal',
    `deal_notes` STRING COMMENT 'Free-text field for additional notes, special terms, or contextual information about the syndication deal. | Column deal_notes (STRING) in rights.rights_syndication_deal',
    `deal_number` STRING COMMENT 'Externally-known business identifier for the syndication deal, used in contracts and communications with licensees. | Column deal_number (STRING) in rights.rights_syndication_deal',
    `deal_start_date` DATE COMMENT 'Date on which the syndication rights become effective and the licensee may begin distribution. | Column deal_start_date (DATE) in rights.rights_syndication_deal',
    `deal_status` STRING COMMENT 'Current lifecycle state of the syndication deal: draft (initial creation), negotiation (under discussion), approved (signed but not yet active), active (currently in effect), suspended (temporarily paused), expired (term ended naturally), terminated (ended early), renewed (extended for additional term). [ENUM-REF-CANDIDATE: draft|negotiation|approved|active|suspended|expired|terminated|renewed — 8 candidates stripped; promote to reference product] | Column deal_status (STRING) in rights.rights_syndication_deal',
    `deal_term_months` STRING COMMENT 'Duration of the syndication deal in months, calculated from start date to end date. Facilitates term-based reporting and renewal planning. | Column deal_term_months (INT) in rights.rights_syndication_deal',
    `drm_required` BOOLEAN COMMENT 'Indicates whether the licensee must implement Digital Rights Management (DRM) technology to protect the content (True) or not (False). | Column drm_required (BOOLEAN) in rights.rights_syndication_deal',
    `exclusivity_indicator` BOOLEAN COMMENT 'Indicates whether the licensee has exclusive syndication rights in the specified territory (True) or non-exclusive rights (False). | Column exclusivity_indicator (BOOLEAN) in rights.rights_syndication_deal',
    `exclusivity_scope` STRING COMMENT 'Detailed description of the exclusivity terms, including any platform-specific, daypart-specific, or window-specific exclusivity conditions. | Column exclusivity_scope (STRING) in rights.rights_syndication_deal',
    `fee_structure_type` STRING COMMENT 'Model for syndication compensation: flat fee (single payment for entire deal), per-episode (payment per episode delivered), per-run (payment per broadcast), revenue share (percentage of licensee revenue), barter (ad inventory exchange), or hybrid (combination of models). | Column fee_structure_type (STRING) in rights.rights_syndication_deal. Valid values are `flat-fee|per-episode|per-run|revenue-share|barter|hybrid`',
    `flat_fee_amount` DECIMAL(18,2) COMMENT 'Total flat fee amount for the syndication deal, if applicable. Null if fee structure is not flat-fee based. | Column flat_fee_amount (DECIMAL(18,2)) in rights.rights_syndication_deal',
    `format_restrictions` STRING COMMENT 'Restrictions on the format or presentation of the content (e.g., no-editing, no-dubbing, original-aspect-ratio-only). | Column format_restrictions (STRING) in rights.rights_syndication_deal',
    `last_modified_by` STRING COMMENT 'User identifier or name of the person who last modified this syndication deal record. | Column last_modified_by (STRING) in rights.rights_syndication_deal',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this syndication deal record was last updated. | Column last_modified_timestamp (TIMESTAMP) in rights.rights_syndication_deal',
    `licensee_type` STRING COMMENT 'Classification of the licensee organization: broadcast station (local terrestrial), cable network, streaming platform (OTT/SVOD/AVOD), digital publisher, MVPD (Multichannel Video Programming Distributor), vMVPD (Virtual MVPD), or international broadcaster. [ENUM-REF-CANDIDATE: broadcast-station|cable-network|streaming-platform|digital-publisher|mvpd|vmvpd|international-broadcaster — 7 candidates stripped; promote to reference product] | Column licensee_type (STRING) in rights.rights_syndication_deal',
    `minimum_guarantee_amount` DECIMAL(18,2) COMMENT 'Minimum guaranteed payment amount that the licensee must pay regardless of actual usage or revenue. Null if no minimum guarantee applies. | Column minimum_guarantee_amount (DECIMAL(18,2)) in rights.rights_syndication_deal',
    `music_sync_license_required` BOOLEAN COMMENT 'Indicates whether separate music synchronization licenses must be secured for the syndicated content (True) or music rights are already cleared (False). | Column music_sync_license_required (BOOLEAN) in rights.rights_syndication_deal',
    `notice_period_days` STRING COMMENT 'Number of days advance notice required for termination or non-renewal of the syndication deal. Null if not applicable. | Column notice_period_days (INT) in rights.rights_syndication_deal',
    `per_episode_fee_amount` DECIMAL(18,2) COMMENT 'Fee amount charged per episode, if applicable. Null if fee structure is not per-episode based. | Column per_episode_fee_amount (DECIMAL(18,2)) in rights.rights_syndication_deal',
    `platform_restrictions` STRING COMMENT 'Comma-separated list of platforms or distribution channels where the licensee is restricted from distributing the content (e.g., linear-only, no-streaming, no-mobile). | Column platform_restrictions (STRING) in rights.rights_syndication_deal',
    `revenue_share_percent` DECIMAL(18,2) COMMENT 'Percentage of licensee revenue shared with Media Broadcasting under a revenue-share fee structure. Null if not applicable. | Column revenue_share_percent (DECIMAL(5,2)) in rights.rights_syndication_deal',
    `run_limit` STRING COMMENT 'Maximum number of times the licensee is permitted to broadcast each episode or title under this syndication deal. Null indicates unlimited runs. | Column run_limit (INT) in rights.rights_syndication_deal',
    `runs_used` STRING COMMENT 'Cumulative count of runs (broadcasts) executed by the licensee to date. Used to track compliance with run limits. | Column runs_used (INT) in rights.rights_syndication_deal',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in rights.rights_syndication_deal',
    `source_system_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in rights.rights_syndication_deal',
    `sublicense_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is permitted to sublicense the content to other distributors (True) or must distribute directly (False). | Column sublicense_permitted (BOOLEAN) in rights.rights_syndication_deal',
    `syndication_type` STRING COMMENT 'Classification of the syndication arrangement: first-run syndication (original content distributed directly to local stations), off-network syndication (previously aired network content), international syndication (cross-border distribution), digital syndication (online/streaming platforms), barter (ad inventory exchange), or cash-plus-barter (hybrid model). | Column syndication_type (STRING) in rights.rights_syndication_deal. Valid values are `first-run|off-network|international|digital|barter|cash-plus-barter`',
    `talent_residuals_applicable` BOOLEAN COMMENT 'Indicates whether talent residual payments (reuse payments to actors, writers, directors) are triggered by this syndication deal (True) or not (False). | Column talent_residuals_applicable (BOOLEAN) in rights.rights_syndication_deal',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in rights.rights_syndication_deal',
    `created_by` STRING COMMENT 'User identifier or name of the person who created this syndication deal record. | Column created_by (STRING) in rights.rights_syndication_deal',
    CONSTRAINT pk_rights_syndication_deal PRIMARY KEY(`rights_syndication_deal_id`)
) COMMENT 'Master record for content syndication agreements under which Media Broadcasting licenses content to third-party broadcasters, streaming platforms, or digital publishers for redistribution. Captures syndication type (first-run syndication, off-network syndication, international syndication, digital syndication), licensee identity, content package or individual title scope, territory, syndication fee structure (flat fee, per-episode, revenue share), run limitations (number of permitted broadcasts), exclusivity, deal start and end dates, and deal status. Distinct from general license agreements — syndication deals have specific run-count and redistribution mechanics. | Unity Catalog table: media_broadcasting_ecm.rights.rights_syndication_deal Aligned with EBU CCDM (Tech 3351) Class Conceptual Data Model semantics. Integrates with Rightsline (rights management).';

