    `payment_amount` DECIMAL(18,2) COMMENT 'The monetary value of the scheduled payment obligation. | Column payment_amount (DECIMAL(18,2)) in rights.license_fee_schedule',
    `payment_approval_status` STRING COMMENT 'Internal approval workflow status for the payment: pending approval (awaiting authorization), approved (cleared for payment), or rejected (payment denied). | Column payment_approval_status (STRING) in rights.license_fee_schedule. Valid values are `pending_approval|approved|rejected`',
    `payment_method` STRING COMMENT 'The instrument or mechanism used to execute the payment: wire transfer, check, ACH (Automated Clearing House), credit card, PayPal, or other. | Column payment_method (STRING) in rights.license_fee_schedule. Valid values are `wire_transfer|check|ach|credit_card|paypal|other`',
