) COMMENT 'Defines the structured payment schedule for license fees owed under a license agreement, including upfront advances, milestone payments, and periodic installments. Captures the parent agreement reference, payment milestone description, scheduled payment date, payment amount, currency, payment type (advance, minimum guarantee installment, per-episode fee, annual license fee), payment status (scheduled, invoiced, paid, overdue), and actual payment date. Enables cash flow forecasting for rights expenditure and feeds the billing domain for invoice generation. | Unity Catalog table: media_broadcasting_ecm.rights.license_fee_schedule Aligned with EBU CCDM (Tech 3351) Class Conceptual Data Model semantics. Integrates with Rightsline (rights management).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`rights`.`rights_audit_event` (
    `rights_audit_event_id` BIGINT COMMENT 'Unique identifier for the rights audit event record. Primary key. | Column rights_audit_event_id (BIGINT) in rights.rights_audit_event',
