    `ip_address` STRING COMMENT 'The IP address from which the rights change was initiated. Supports security audit and geographic access analysis. May be IPv4 or IPv6 format. | Column ip_address (STRING) in rights.rights_audit_event',
    `new_value` DECIMAL(18,2) COMMENT 'The value of the changed field after the modification occurred. Stored as string representation to accommodate all data types. NULL for deletion events. | Column new_value (DECIMAL(18,2)) in rights.rights_audit_event',
    `previous_value` DECIMAL(18,2) COMMENT 'The value of the changed field before the modification occurred. Stored as string representation to accommodate all data types. NULL for new record creation events. | Column previous_value (DECIMAL(18,2)) in rights.rights_audit_event',
    `record_hash` STRING COMMENT 'Cryptographic hash (e.g., SHA-256) of the audit event record to ensure immutability and detect tampering. Supports forensic integrity verification. | Column record_hash (STRING) in rights.rights_audit_event',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in rights.rights_audit_event',
    `source_system_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in rights.rights_audit_event',
    `territory_affected` STRING COMMENT 'Geographic territory or market affected by the rights change (e.g., USA, GBR, Worldwide). Uses three-letter ISO 3166-1 alpha-3 country codes or territory groupings. | Column territory_affected (STRING) in rights.rights_audit_event',
    `transaction_reference` STRING COMMENT 'Unique identifier for the database transaction or batch operation that committed this change. Enables grouping of related audit events within a single transaction. | Column transaction_reference (STRING) in rights.rights_audit_event',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in rights.rights_audit_event',
    `window_type_affected` STRING COMMENT 'The content distribution window type affected by this rights change (e.g., theatrical, SVOD, AVOD, TVOD, linear broadcast, syndication). NULL if change does not affect windowing. [ENUM-REF-CANDIDATE: theatrical|SVOD|AVOD|TVOD|linear|syndication|home_video — 7 candidates stripped; promote to reference product] | Column window_type_affected (STRING) in rights.rights_audit_event',
    CONSTRAINT pk_rights_audit_event PRIMARY KEY(`rights_audit_event_id`)
) COMMENT 'Immutable audit log of all material changes to rights grants, license agreements, content windows, and holdback records within the rights domain. Captures event type (rights grant created, window modified, holdback added, agreement terminated, clearance overridden), the affected entity type and ID, previous and new values of changed fields, change timestamp, initiating user or system, change reason, and approval reference if applicable. Supports regulatory compliance (FCC, Ofcom), legal dispute resolution, and SOX financial audit trails for rights expenditure. | Unity Catalog table: media_broadcasting_ecm.rights.rights_audit_event Aligned with EBU CCDM (Tech 3351) Class Conceptual Data Model semantics. Integrates with Rightsline (rights management).';

