    `hfa_song_code` STRING COMMENT 'Harry Fox Agency song code',
    `interactive_streams` BIGINT COMMENT 'Number of interactive (on-demand) streams',
    `iswc_code` STRING COMMENT 'International Standard Musical Work Code',
    `mlc_reference_number` STRING COMMENT 'MLC confirmation/reference number',
    `net_royalty_amount` DECIMAL(18,2) COMMENT 'Net mechanical royalty amount after fees',
    `non_interactive_streams` BIGINT COMMENT 'Number of non-interactive streams',
    `payment_date` DATE COMMENT 'Date royalty payment was made',
    `report_period_end_date` DATE COMMENT 'End date of reporting period',
    `report_period_start_date` DATE COMMENT 'Start date of reporting period',
    `report_status` STRING COMMENT 'Status: DRAFT, SUBMITTED, ACCEPTED, REJECTED, AMENDED',
    `report_submission_date` DATE COMMENT 'Date report was submitted to MLC',
    `statutory_rate` DECIMAL(18,2) COMMENT 'Statutory mechanical royalty rate applied',
    `territory_code` STRING COMMENT 'Territory code for royalty calculation',
    `total_downloads` BIGINT COMMENT 'Total number of downloads in reporting period',
    `total_streams` BIGINT COMMENT 'Total number of streams in reporting period',
    `unmatched_usage_flag` BOOLEAN COMMENT 'Whether report contains unmatched/unclaimed works',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_mechanical_royalty_report PRIMARY KEY(`mechanical_royalty_report_id`)
) COMMENT 'Mechanical royalty report for US Music Modernization Act compliance via the Mechanical Licensing Collective (MLC)';

